using E_POS.Domain.Modules.AccessControl.Entities;
using E_POS.Domain.Modules.CatalogProduct.Entities;
using E_POS.Domain.Modules.Inventory.Entities;
using E_POS.Domain.Modules.TenantFoundation.Entities;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;

namespace E_POS.Infrastructure.Modules.Inventory.Configurations;
public sealed class StocktakeSessionConfiguration : IEntityTypeConfiguration<StocktakeSession>
{
    public void Configure(EntityTypeBuilder<StocktakeSession> builder)
    { builder.ToTable("stocktake_sessions"); builder.HasKey(x => x.Id).HasName("pk_stocktake_sessions"); builder.Property(x => x.Id).HasColumnName("id"); builder.Property(x => x.CreatedAt).HasColumnName("created_at").HasColumnType("timestamp with time zone").IsRequired(); builder.Property(x => x.CreatedBy).HasColumnName("created_by_tenant_user_id").IsRequired(false); builder.Property(x => x.UpdatedAt).HasColumnName("updated_at").HasColumnType("timestamp with time zone").IsRequired(); builder.Property(x => x.UpdatedBy).HasColumnName("updated_by_tenant_user_id").IsRequired(false); builder.Property(x => x.TenantId).HasColumnName("tenant_id").IsRequired(); builder.Property(x => x.StocktakeNumber).HasColumnName("stocktake_number").HasColumnType("varchar(80)").HasMaxLength(80).IsRequired(); builder.Property(x => x.InventoryLocationId).HasColumnName("inventory_location_id").IsRequired(); builder.Property(x => x.StocktakeType).HasColumnName("stocktake_type").HasColumnType("varchar(40)").HasMaxLength(40).IsRequired(); builder.Property(x => x.StocktakeStatus).HasColumnName("stocktake_status").HasColumnType("varchar(40)").HasMaxLength(40).IsRequired(); builder.Property(x => x.IsBlindCount).HasColumnName("is_blind_count").HasDefaultValue(false).IsRequired(); builder.Property(x => x.SnapshotAt).HasColumnName("snapshot_at").HasColumnType("timestamp with time zone").IsRequired(); builder.Property(x => x.StartedAt).HasColumnName("started_at").HasColumnType("timestamp with time zone").IsRequired(false); builder.Property(x => x.CompletedAt).HasColumnName("completed_at").HasColumnType("timestamp with time zone").IsRequired(false); builder.Property(x => x.PostedAt).HasColumnName("posted_at").HasColumnType("timestamp with time zone").IsRequired(false); builder.Property(x => x.StartedByTenantUserId).HasColumnName("started_by_tenant_user_id").IsRequired(false); builder.Property(x => x.CompletedByTenantUserId).HasColumnName("completed_by_tenant_user_id").IsRequired(false); builder.Property(x => x.PostedByTenantUserId).HasColumnName("posted_by_tenant_user_id").IsRequired(false); builder.Property(x => x.GeneratedStockAdjustmentId).HasColumnName("generated_stock_adjustment_id").IsRequired(false); builder.Property(x => x.Notes).HasColumnName("notes").HasColumnType("text").IsRequired(false); builder.HasOne<Tenant>().WithMany().HasForeignKey(x => x.TenantId).OnDelete(DeleteBehavior.Restrict).HasConstraintName("fk_stocktake_sessions_tenant_id_tenants"); builder.HasOne<InventoryLocation>().WithMany().HasForeignKey(x => x.InventoryLocationId).OnDelete(DeleteBehavior.Restrict).HasConstraintName("fk_stocktake_sessions_inventory_location_id_inventory_locations"); builder.HasOne<StockAdjustment>().WithMany().HasForeignKey(x => x.GeneratedStockAdjustmentId).OnDelete(DeleteBehavior.Restrict).HasConstraintName("fk_stocktake_sessions_generated_stock_adjustment_id_stock_adjustments"); builder.HasIndex(x => new { x.TenantId, x.StocktakeNumber }).IsUnique().HasDatabaseName("uq_stocktake_sessions_tenant_id_stocktake_number"); }
